import{_ as a,o as t,c as s,aB as i}from"./chunks/framework.Bi5A6EOb.js";const g=JSON.parse('{"title":"Aerosols","description":"","frontmatter":{},"headers":[],"relativePath":"pages/Aerosols/Overview.md","filePath":"pages/Aerosols/Overview.md","lastUpdated":null}'),r={name:"pages/Aerosols/Overview.md"};function o(l,e,n,d,h,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="Aerosols" tabindex="-1">Aerosols <a class="header-anchor" href="#Aerosols" aria-label="Permalink to &quot;Aerosols {#Aerosols}&quot;">​</a></h1><p><strong>For:</strong> users reading aerosol inputs and developers stabilizing aerosol scheme support.</p><p><strong>Next:</strong> <a href="./../IO/Overview">Configure a Scene</a>, <a href="./../concepts/03b_scattering">Mie &amp; Rayleigh (Concepts)</a>, <a href="./../api_reference">Library</a>.</p><p>The <code>Aerosols</code> module is a user-facing framework for aerosol input data, refractive-index lookup tables, and scheme-specific optical-property preparation. This API is still being stabilized after the <code>sanghavi-unified</code> merge, so treat it as available but more likely to evolve than the CoreRT, Absorption, and Scattering APIs.</p><h2 id="Supported-Schemes" tabindex="-1">Supported Schemes <a class="header-anchor" href="#Supported-Schemes" aria-label="Permalink to &quot;Supported Schemes {#Supported-Schemes}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Scheme</th><th style="text-align:right;">Type</th><th style="text-align:right;">Input style</th><th style="text-align:right;">Use case</th></tr></thead><tbody><tr><td style="text-align:right;">TOMAS-15</td><td style="text-align:right;"><code>TOMAS15Scheme</code></td><td style="text-align:right;">Size-resolved concentrations in 15 logarithmic diameter bins</td><td style="text-align:right;">Microphysics-aware aerosol columns</td></tr><tr><td style="text-align:right;">Two-moment</td><td style="text-align:right;"><code>TwoMomentScheme</code></td><td style="text-align:right;">AOD, effective radius, and fixed geometric width per species</td><td style="text-align:right;">Compact aerosol-state inputs from chemistry or retrieval systems</td></tr></tbody></table><p>Both schemes are configured from YAML and read from NetCDF through <code>read_aerosol_data</code>. The returned <code>AerosolData</code> stores the scheme, species data, coordinates, and NetCDF metadata.</p><h2 id="Refractive-Indices" tabindex="-1">Refractive Indices <a class="header-anchor" href="#Refractive-Indices" aria-label="Permalink to &quot;Refractive Indices {#Refractive-Indices}&quot;">​</a></h2><p>The refractive-index database is separate from the aerosol state:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> vSmartMOM</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> vSmartMOM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Aerosols</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">load_refractive_index_database</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;refractive_indices.yaml&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> vSmartMOM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Aerosols</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">get_refractive_index</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(db, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sulfate_suso&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.55</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Wavelengths are in micrometers. <code>get_refractive_index</code> interpolates the real and imaginary parts linearly and returns a complex refractive index.</p><h2 id="Relationship-To-Scattering" tabindex="-1">Relationship To Scattering <a class="header-anchor" href="#Relationship-To-Scattering" aria-label="Permalink to &quot;Relationship To Scattering {#Relationship-To-Scattering}&quot;">​</a></h2><p><code>Aerosols</code> handles data ingestion and scheme organization. The lower-level Mie and Greek-coefficient calculations are explained in <a href="./../concepts/03b_scattering">Mie &amp; Rayleigh (Concepts)</a>. In a complete workflow, aerosol input data are converted into optical properties that the CoreRT layer assembly can consume.</p><h2 id="Current-Caveats" tabindex="-1">Current Caveats <a class="header-anchor" href="#Current-Caveats" aria-label="Permalink to &quot;Current Caveats {#Current-Caveats}&quot;">​</a></h2><ul><li><p>The module is public but still WIP; names and configuration details may be cleaned up before registration.</p></li><li><p>TOMAS-15 and two-moment support are present; additional schemes should be added through new <code>AerosolScheme</code> subtypes rather than one large parser branch.</p></li><li><p>Heavy NetCDF fixtures are not part of the unit-test path.</p></li></ul><h2 id="Useful-APIs" tabindex="-1">Useful APIs <a class="header-anchor" href="#Useful-APIs" aria-label="Permalink to &quot;Useful APIs {#Useful-APIs}&quot;">​</a></h2><ul><li><p><code>AerosolScheme</code>, <code>TOMAS15Scheme</code>, <code>TwoMomentScheme</code></p></li><li><p><code>AerosolData</code>, <code>AerosolSpeciesData</code></p></li><li><p><code>RefractiveIndexDatabase</code>, <code>RefractiveIndexLUT</code></p></li><li><p><code>read_aerosol_data</code>, <code>load_refractive_index_database</code>, <code>get_refractive_index</code></p></li><li><p><code>list_species</code>, <code>wavelength_range</code></p></li></ul>`,17)])])}const k=a(r,[["render",o]]);export{g as __pageData,k as default};
